const WebSocket = require('ws');

const wss = new WebSocket.Server({ port: 8080 });

wss.on('connection', (ws) => {
    ws.on('message', (message) => {
        const command = JSON.parse(message);
        
        switch (command.type) {
            case 'build':
                buildUnit(command.unitType, command.position);
                break;
            case 'attack':
                attackTarget(command.attackerId, command.targetId);
                break;
            case 'move':
                moveUnit(command.unitId, command.newPosition);
                break;
            default:
                console.log('Unknown command type:', command.type);
        }
    });
});

